#!/usr/bin/env bash
# topic-1.sh — 心理 决策助手 for 青少年心理健康教育.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="青少年心理健康教育"
TOPIC="心理"

usage() {
  cat <<EOF
topic-1.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 4 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-1.sh             # interactive
  ./topic-1.sh --dry-run   # walk through but no file
  ./topic-1.sh --json      # JSON to stdout
  ./topic-1.sh --explain   # show backing playbook rules + mental models
  ./topic-1.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 心理 主题下的 playbook 规则组合成交互树。

基于 4 条规则:
  • 如果 家长质疑学校心理健康项目 → 则 : 用数据回应(Durlak 2011 meta-analysis 显示 SEL 提升学业 11 百分位点),不用意识形
  • 如果 选用数字心理健康工具 → 则 : 确认 HIPAA/FERPA 合规 + 有 RCT 支持 + 不替代人际干预。案例: Woebot 有多项 RCT 
  • 如果 在中国学校推行心理健康课 → 则 : 必须对接教育部《中小学心理健康教育指导纲要》,课时从班会课/综合实践活动切入而非要求新增课时。案例: 多地学校在"双
  • 如果 心理健康培训预算有限 → 则 : 优先投资 Youth Mental Health First Aid(YMHFA)——8 小时培训让非专业人员具备基

相关心智模型:
  • 发展适配优先 — 青春期不是成人的缩小版: 青少年的大脑、认知和情绪发展处于独特阶段——前额叶皮层 25 岁前未完全成熟、杏仁核反应性高、同伴影响权重超越成人直觉——任何干预方案必须以发展阶段为锚点设计,而非照搬成人模型。
  • 预防优于治疗 — MTSS 三级金字塔: 心理健康教育的核心逻辑是三级预防——Tier 1 全员预防(SEL/心理课)覆盖约 80% 的学生、Tier 2 小组干预(针对筛查出的 at-risk 群体)覆盖约 15%、Tier 3 个别临床干

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "家长质疑学校心理健康项目"
  "选用数字心理健康工具"
  "在中国学校推行心理健康课"
  "心理健康培训预算有限"
)
declare -a RULE_ACTIONS=(
  ": 用数据回应(Durlak 2011 meta-analysis 显示 SEL 提升学业 11 百分位点),不用意识形态辩论。案例: 美国部分学区面对保守派 anti-SEL 运动时用学业数据说服校董会(T01-S005)"
  ": 确认 HIPAA/FERPA 合规 + 有 RCT 支持 + 不替代人际干预。案例: Woebot 有多项 RCT 但明确标注\"不适用于危机情境\"(T02-S037)"
  ": 必须对接教育部《中小学心理健康教育指导纲要》,课时从班会课/综合实践活动切入而非要求新增课时。案例: 多地学校在\"双减\"后利用释放的课时增加心理健康内容(T06-S020, T01-S018)"
  ": 优先投资 Youth Mental Health First Aid(YMHFA)——8 小时培训让非专业人员具备基本识别和初步应对能力,性价比最高。案例: 美国 YMHFA 已培训约 300 万成人(约业内估, T02-S009)"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-1-decision"
fi
